(function(){
  PyLearn.createEditor({
    containerId: 'editor-ip',
    initialCode: 'score = 75\n\n# Write your if/else here\n',
    label: 'Mini Practice',
    validate: async function(output, error, code) {
      if (error) return { pass: false, message: '\u274c Problem: ' + error };
      var stripped = code.replace(/^score\s*=.*$/m, '');
      // Test 1: score 75 should win
      var r1 = await PyLearn.runPython('score = 75\n' + stripped);
      if (r1.error) return { pass: false, message: '\u274c Problem: ' + r1.error };
      if (r1.output.trim() !== 'You win!') return { pass: false, message: '\u274c When score is 75, we expected: You win!  But got: \"' + r1.output.trim() + '\"' };
      // Test 2: score 30 should fail
      var r2 = await PyLearn.runPython('score = 30\n' + stripped);
      if (r2.error) return { pass: false, message: '\u274c Problem: ' + r2.error };
      if (r2.output.trim() !== 'Try again') return { pass: false, message: '\u274c When score is 30, we expected: Try again  But got: \"' + r2.output.trim() + '\"' };
      return { pass: true, message: '\u2705 Brilliant! Both cases work.' };
    },
    onPass: async function() { await window.__markStepComplete(); }
  });
})();

