(function(){
  var starter = 'def check_password(username, password):\n    accounts = {"alice": "Sunshine7", "bob": "Football3", "admin": "Adm1n!Pass", "guest": "guest"}\n    if username not in accounts:\n        return False\n    return accounts[username] == password\n\n# 1. Ask for the username\n# 2. Ask for the password\n# 3. Use check_password\n# 4. Print Access granted or Access denied\n';
  PyLearn.createEditor({
    containerId: 'editor-ch',
    initialCode: starter,
    label: 'Login Screen Challenge',
    validate: async function(output, error, code) {
      if (error) return { pass: false, message: '\u274c There is a problem: ' + error };
      // Test correct login
      var r1 = await PyLearn.runPython(code, { inputFn: (function(){ var q=['alice','Sunshine7']; return async function(){ return q.shift()||''; }; })() });
      if (r1.error) return { pass: false, message: '\u274c Problem with correct login: ' + r1.error };
      if (r1.output.trim() !== 'Access granted') return { pass: false, message: '\u274c With alice / Sunshine7 we should see: Access granted. We saw: \"' + r1.output.trim() + '\"' };
      // Test wrong password
      var r2 = await PyLearn.runPython(code, { inputFn: (function(){ var q=['alice','wrongpass']; return async function(){ return q.shift()||''; }; })() });
      if (r2.error) return { pass: false, message: '\u274c Problem with wrong password: ' + r2.error };
      if (r2.output.trim() !== 'Access denied') return { pass: false, message: '\u274c With alice / wrongpass we should see: Access denied. We saw: \"' + r2.output.trim() + '\"' };
      // Test unknown user
      var r3 = await PyLearn.runPython(code, { inputFn: (function(){ var q=['nobody','anything']; return async function(){ return q.shift()||''; }; })() });
      if (r3.error) return { pass: false, message: '\u274c Problem with unknown user: ' + r3.error };
      if (r3.output.trim() !== 'Access denied') return { pass: false, message: '\u274c With an unknown user we should see: Access denied. We saw: \"' + r3.output.trim() + '\"' };
      return { pass: true, message: '\u2705 Amazing! Your login screen works perfectly!' };
    },
    onPass: async function() { await window.__markStepComplete(); }
  });
})();

(function(){
  var VALIDATOR = 'def check_password(username, password):\n    accounts = {"alice": "Sunshine7", "bob": "Football3", "admin": "Adm1n!Pass", "guest": "guest"}\n    if username not in accounts:\n        return False\n    return accounts[username] == password\n\n';

  var streak = 0;
  var best   = parseInt(localStorage.getItem('pylearn_login_best') || '0', 10);
  document.getElementById('el-best').textContent = best;

  var challenges = [
    {
      prompt: 'Use <code>print</code> to show the word: <strong>Hello</strong>',
      note: '',
      inputs: [],
      starter: '',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        return r.output.trim() === 'Hello' ? null : '\u274c We need exactly: Hello. You showed: \"' + r.output.trim() + '\"';
      }
    },
    {
      prompt: 'Use <strong>one</strong> <code>print</code> with a comma to show: <strong>Score: 100</strong>',
      note: '',
      inputs: [],
      starter: '',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        if (r.output.trim() !== 'Score: 100') return '\u274c We need: Score: 100. You showed: \"' + r.output.trim() + '\"';
        if (!/,/.test(code)) return '\u26a0\ufe0f Right answer, but please use a comma in print.';
        return null;
      }
    },
    {
      prompt: 'A variable <code>name = "Sam"</code> is already there. Use <code>print</code> with a comma to show: <strong>Hello Sam</strong> (using the variable, not the word "Sam" in quotes).',
      note: '',
      inputs: [],
      starter: 'name = "Sam"\n# Show: Hello Sam\n',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        if (r.output.trim() !== 'Hello Sam') return '\u274c We need: Hello Sam. You showed: \"' + r.output.trim() + '\"';
        if (!/name\b/.test(code.split('=').slice(1).join('='))) return '\u26a0\ufe0f Use the variable <code>name</code> in your print, not the word in quotes.';
        return null;
      }
    },
    {
      prompt: 'Ask the user <code>"What is your name? "</code> and store the answer. Then show <strong>Hi</strong> followed by the name. (Hint: use a comma in print.)',
      note: '&#x1F4A1; The user will type: <strong>Maya</strong>',
      inputs: ['Maya'],
      starter: '',
      check: async function(code) {
        var r = await PyLearn.runPython(code, async function(){ return 'Maya'; });
        if (r.error) return '\u274c Problem: ' + r.error;
        return r.output.trim() === 'Hi Maya' ? null : '\u274c We need: Hi Maya. You showed: \"' + r.output.trim() + '\"';
      }
    },
    {
      prompt: 'A variable <code>age</code> is set. Show <strong>Adult</strong> if age is 18 or more, otherwise show <strong>Child</strong>.',
      note: '',
      inputs: [],
      starter: 'age = 25\n# Write your if/else\n',
      check: async function(code) {
        var stripped = code.replace(/^age\s*=.*$/m, '');
        var cases = [{a:25, e:'Adult'}, {a:10, e:'Child'}, {a:18, e:'Adult'}];
        for (var i = 0; i < cases.length; i++) {
          var c = cases[i];
          var r = await PyLearn.runPython('age = ' + c.a + '\n' + stripped);
          if (r.error) return '\u274c Problem when age=' + c.a + ': ' + r.error;
          if (r.output.trim() !== c.e) return '\u274c When age=' + c.a + ' we need: ' + c.e + '. You showed: \"' + r.output.trim() + '\"';
        }
        return null;
      }
    },
    {
      prompt: 'Ask <code>"Favourite colour: "</code>. Then show <strong>Nice colour!</strong> if they typed <code>blue</code>, otherwise show <strong>Cool</strong>.',
      note: '&#x1F4A1; Tested with both <strong>blue</strong> and <strong>red</strong>.',
      inputs: ['blue'],
      starter: '',
      check: async function(code) {
        var r1 = await PyLearn.runPython(code, async function(){ return 'blue'; });
        if (r1.error) return '\u274c Problem: ' + r1.error;
        if (r1.output.trim() !== 'Nice colour!') return '\u274c When they type "blue" we need: Nice colour! You showed: \"' + r1.output.trim() + '\"';
        var r2 = await PyLearn.runPython(code, async function(){ return 'red'; });
        if (r2.error) return '\u274c Problem: ' + r2.error;
        if (r2.output.trim() !== 'Cool') return '\u274c When they type "red" we need: Cool. You showed: \"' + r2.output.trim() + '\"';
        return null;
      }
    },
    {
      prompt: 'A variable <code>username</code> is set. If it equals <code>"admin"</code> show <strong>Welcome boss</strong>, otherwise show <strong>Hello user</strong>.',
      note: '',
      inputs: [],
      starter: 'username = "admin"\n',
      check: async function(code) {
        var stripped = code.replace(/^username\s*=.*$/m, '');
        var cases = [{u:'admin', e:'Welcome boss'}, {u:'sam', e:'Hello user'}];
        for (var i = 0; i < cases.length; i++) {
          var c = cases[i];
          var r = await PyLearn.runPython('username = "' + c.u + '"\n' + stripped);
          if (r.error) return '\u274c Problem when username="' + c.u + '": ' + r.error;
          if (r.output.trim() !== c.e) return '\u274c With username="' + c.u + '" we need: ' + c.e + '. You showed: \"' + r.output.trim() + '\"';
        }
        return null;
      }
    },
    {
      prompt: 'Use the password checker. Use <code>check_password("bob", "Football3")</code>. If True, show <strong>Hi Bob!</strong>, otherwise show <strong>Wrong password</strong>.',
      note: '',
      inputs: [],
      starter: '',
      check: async function(code) {
        var fullCode = VALIDATOR + code.replace(/def check_password[\s\S]*?return\s+accounts\[username\]\s*==\s*password\s*\n?/g, '');
        var r = await PyLearn.runPython(fullCode);
        if (r.error) return '\u274c Problem: ' + r.error;
        if (r.output.trim() === 'Hi Bob!') return null;
        return '\u274c We need: Hi Bob! You showed: \"' + r.output.trim() + '\"';
      }
    },
    {
      prompt: 'Ask <code>"Username: "</code> and <code>"Password: "</code>. Use the password checker. If correct show <strong>Logged in</strong>, otherwise show <strong>Try again</strong>.',
      note: '&#x1F4A1; Tested with alice / Sunshine7 (correct) and alice / wrong (incorrect).',
      inputs: ['alice', 'Sunshine7'],
      starter: '',
      check: async function(code) {
        var fullCode = VALIDATOR + code.replace(/def check_password[\s\S]*?return\s+accounts\[username\]\s*==\s*password\s*\n?/g, '');
        var r1 = await PyLearn.runPython(fullCode, (function(){ var q=['alice','Sunshine7']; return async function(){ return q.shift()||''; }; })());
        if (r1.error) return '\u274c Problem: ' + r1.error;
        if (r1.output.trim() !== 'Logged in') return '\u274c With correct password we need: Logged in. You showed: \"' + r1.output.trim() + '\"';
        var r2 = await PyLearn.runPython(fullCode, (function(){ var q=['alice','wrong']; return async function(){ return q.shift()||''; }; })());
        if (r2.error) return '\u274c Problem: ' + r2.error;
        if (r2.output.trim() !== 'Try again') return '\u274c With wrong password we need: Try again. You showed: \"' + r2.output.trim() + '\"';
        return null;
      }
    },
    {
      prompt: 'Make two variables: <code>game = "Minecraft"</code> and <code>players = 4</code>. Show on one line: <strong>Game: Minecraft Players: 4</strong>',
      note: '',
      inputs: [],
      starter: '',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        if (r.output.trim() !== 'Game: Minecraft Players: 4') return '\u274c We need: Game: Minecraft Players: 4. You showed: \"' + r.output.trim() + '\"';
        if (!/game\s*=/.test(code) || !/players\s*=/.test(code)) return '\u26a0\ufe0f Make sure you create both variables: game and players.';
        return null;
      }
    }
  ];

  var currentIdx = -1;

  function pickChallenge() {
    var next;
    do { next = Math.floor(Math.random() * challenges.length); } while (next === currentIdx && challenges.length > 1);
    currentIdx = next;
    return challenges[next];
  }

  function loadChallenge() {
    var ch = pickChallenge();
    document.getElementById('el-prompt').innerHTML = ch.prompt;
    document.getElementById('el-sim-note').innerHTML = ch.note || '';

    var wrap = document.getElementById('editor-endless');
    wrap.innerHTML = '';

    PyLearn.createEditor({
      containerId: 'editor-endless',
      persist: false,
      initialCode: ch.starter || '# Write your code\n',
      label: 'Endless Mode',
      validate: async function(output, error, code) {
        var msg = await challenges[currentIdx].check(code);
        if (msg) return { pass: false, message: msg };
        return { pass: true, message: '\u2705 Correct! Loading next challenge...' };
      },
      onPass: async function() {
        streak++;
        if (streak > best) {
          best = streak;
          localStorage.setItem('pylearn_login_best', best);
          document.getElementById('el-best').textContent = best;
        }
        document.getElementById('el-streak').textContent = streak;
        setTimeout(loadChallenge, 1300);
      }
    });

  }

  document.getElementById('el-new').onclick = function() {
    streak = 0;
    document.getElementById('el-streak').textContent = streak;
    loadChallenge();
  };

  loadChallenge();
})();
